import socket
import json

class GameServer:
    def __init__(self):
        self.players = []
        self.game_state = {}

    def handle_udp_query(self, data, address):
        if data == "status":
            return json.dumps({"players": self.players, "game_state": self.game_state})

    def listen(self):
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.bind(("0.0.0.0", 1234))
        while True:
            data, address = sock.recvfrom(1024)
            self.handle_udp_query(data, address)